/// Extract content from a byte array.
///
/// This is the main entry point for in-memory extraction. It performs the following steps:
/// 1. Validate MIME type
/// 2. Handle legacy format conversion if needed
/// 3. Select appropriate extractor from registry
/// 4. Extract content
/// 5. Run post-processing pipeline
///
/// # Arguments
///
/// * `content` - The byte array to extract
/// * `mime_type` - MIME type of the content
/// * `config` - Extraction configuration
///
/// # Returns
///
/// An `ExtractionResult` containing the extracted content and metadata.
///
/// # Errors
///
/// Returns `KreuzbergError::Validation` if MIME type is invalid.
/// Returns `KreuzbergError::UnsupportedFormat` if MIME type is not supported.
///
/// # Example
///
/// ```rust,no_run
/// use kreuzberg::core::extractor::extract_bytes;
/// use kreuzberg::core::config::ExtractionConfig;
///
/// # async fn example() -> kreuzberg::Result<()> {
/// let config = ExtractionConfig::default();
/// let bytes = b"Hello, world!";
/// let result = extract_bytes(bytes, "text/plain", &config).await?;
/// println!("Content: {}", result.content);
/// # Ok(())
/// # }
/// ```
#[rustler::nif(schedule = "DirtyCpu")]
pub fn extract_bytes_async(
    content: Vec<u8>,
    mime_type: String,
    config: Option<String>,
) -> Result<ExtractionResult, String> {
    let config_core: Option<kreuzberg::ExtractionConfig> = config
        .map(|s| serde_json::from_str::<kreuzberg::ExtractionConfig>(&s))
        .transpose()
        .map_err(|e| e.to_string())?;
    let rt = tokio::runtime::Runtime::new().map_err(|e| e.to_string())?;
    let result = rt
        .block_on(async {
            kreuzberg::extract_bytes(
                &content,
                &mime_type,
                config_core.as_ref().unwrap_or(&Default::default()),
            )
            .await
        })
        .map_err(|e| e.to_string())?;
    Ok(result.into())
}

/// Extract content from a file.
